import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './Login.css';
import img1 from '../Assets/camping.jpg';
import img2 from '../Assets/camping2.jpg';
import img3 from '../Assets/night.jpg';

const Login = () => {
  const [formData, setFormData] = useState({ email: '', password: '' });
  const [errors, setErrors] = useState({});
  const [currentIndex, setCurrentIndex] = useState(0);
  const navigate = useNavigate();

  // Validate form inputs
  const validate = () => {
    const newErrors = {};
    if (!formData.email) newErrors.email = 'Email is required';
    if (!formData.password) newErrors.password = 'Password is required';
    return newErrors;
  };

  // Handle login form submission
  const handleSubmit = (e) => {
    e.preventDefault();

    // Validate input fields
    const validationErrors = validate();
    if (Object.keys(validationErrors).length > 0) {
      setErrors(validationErrors);
      return;
    }

    // Retrieve user data from local storage
    const storedUser = JSON.parse(localStorage.getItem('user')); // Key should match the one used during signup

    // Check if user data exists and matches
    if (storedUser) {
      if (storedUser.email === formData.email && storedUser.password === formData.password) {
        alert('Login successful!');
        console.log('Login successful:', formData);
        navigate('/dashboard'); // Redirect to dashboard or another page
      } else {
        alert('Invalid email or password');
      }
    } else {
      alert('User does not exist. Please sign up.');
    }
  };

  // Images for the slideshow
  const images = [img1, img2, img3];

  // Slideshow logic
  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentIndex((prevIndex) => (prevIndex + 1) % images.length);
    }, 3000); // Slide every 3 seconds
    return () => clearInterval(interval);
  }, [images.length]);

  return (
    <div className="login-container">
      <div className="login-image">
        {images.map((image, index) => (
          <img
            key={index}
            src={image}
            alt={`Slide ${index}`}
            className={index === currentIndex ? 'active' : 'inactive'}
          />
        ))}
      </div>
      <div className="login-form">
        <form onSubmit={handleSubmit}>
          <h2>Log In</h2>
          <div className="form-group">
            <label htmlFor="email">Contact/Email</label>
            <input
              type="email"
              id="email"
              name="email"
              value={formData.email}
              onChange={(e) => setFormData({ ...formData, email: e.target.value })}
              placeholder="Enter your email"
            />
            {errors.email && <span className="error">{errors.email}</span>}
          </div>
          <div className="form-group">
            <label htmlFor="password">Password</label>
            <input
              type="password"
              id="password"
              name="password"
              value={formData.password}
              onChange={(e) => setFormData({ ...formData, password: e.target.value })}
              placeholder="Enter your password"
            />
            {errors.password && <span className="error">{errors.password}</span>}
          </div>
          <div className="checkbox-container">
            <div>
              <input type="checkbox" id="terms" />
            </div>
            <div>
              <label htmlFor="terms">
                <a href="#">I accept all terms</a>
              </label>
            </div>
          </div>
          <div className="links">
            <a href="/forgot-password" className="forgot-password-link">Forgot password?</a>
            <a onClick={() => navigate('/create-account')} className="create-account-link">Create account</a>
          </div>
          <button type="submit" className="login-button">Log In</button>
        </form>
      </div>
    </div>
  );
};

export default Login;
